fn main() {
    struct Book {
        title: String,
        author: String,
        pages: u32,
    }

    let book = Book {
        title: String::from("Rust Programming"),
        author: String::from("John Doe"),
        pages: 350,
    };

    println!("{} by {}, {} pages", book.title, book.author, book.pages);
}
